import { getDefaultQuery, retrieveKeyword } from 'api';

const defaults = await getDefaultQuery();
const result = await retrieveKeyword({
  query: defaults.query,
  speaker: defaults.speaker,
  date: defaults.date
});

export default {
  query: result.query,
  speaker: result.speaker,
  date: result.date,
  matches: result.matches
};

